#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    bool isCyclicUtil(vector<vector<int>>& graph, int V)
    {
        vector<int> low(V), disc(V);
        function<bool(int, int)> dfs = [&](int node, int parent) {
            if (graph[node].size() == 0) return low[node] = disc[node] = node;
            low[node] = node;
            for (int v : graph[node])
                if (v == parent) continue;
                if (dfs(v, node)) return true;
                low[node] = min(low[node], disc[v]);
            return false;
        };
        return dfs(0, -1);
    }
};

